import { type Brand } from '../../data/tokens';

export type ButtonType =
  | 'Full Button'
  | 'Icon Only'
  | 'Social Login'
  | 'GooglePay'
  | 'ApplePay'
  | 'PayPal';

export type ButtonVariant =
  | 'Primary'
  | 'Secondary'
  | 'Tertiary'
  | 'White'
  | 'Destructive'
  | 'Destructive-Text';

export type ButtonSize = 'Default' | 'Small' | 'Tiny';
export type ButtonState = 'Default' | 'Hover' | 'Focus' | 'Active' | 'Disabled' | 'Loading';

interface ButtonLiveProps {
  buttonType?: ButtonType;
  variant?: ButtonVariant;
  size?: ButtonSize;
  state?: ButtonState;
  label?: string;
  showIconLeft?: boolean;
  showIconRight?: boolean;
  brand?: Brand;
}

// Full Button size → height + paddingX
const FULL_SIZE: Record<ButtonSize, { height: string; paddingX: string; fontSize: string }> = {
  Default: { height: '64px', paddingX: '24px', fontSize: '14px' },
  Small:   { height: '52px', paddingX: '20px', fontSize: '14px' },
  Tiny:    { height: '42px', paddingX: '16px', fontSize: '12px' },
};

// Icon Only size → square dimension
const ICON_ONLY_SIZE: Record<ButtonSize, string> = {
  Default: '60px',
  Small:   '52px',
  Tiny:    '40px',
};

