// ─── Full Button variant style definitions ────────────────────────────────────
const VARIANT_STYLES: Record<ButtonVariant, {
  bg: string; fg: string; border: string;
  overlayColor: string; hoverOp: number; activeOp: number; focusOp: number;
}> = {
  Primary: {
    bg: 'var(--atom-background-primary-bg-primary-default)',
    fg: 'var(--atom-foreground-primary-fg-brand-primary-inverse)',
    border: 'none',
    overlayColor: 'rgba(255,255,255,1)', hoverOp: 0.12, activeOp: 0.22, focusOp: 0.08,
  },
  Secondary: {
    bg: 'transparent',
    fg: 'var(--atom-foreground-primary-fg-brand-primary)',
    border: '1px solid var(--atom-border-default-border-default-brand)',
    overlayColor: 'var(--atom-background-primary-bg-primary-default)', hoverOp: 0.06, activeOp: 0.12, focusOp: 0.04,
  },
  Tertiary: {
    bg: 'transparent',
    fg: 'var(--atom-foreground-core-fg-link)',
    border: 'none',
    overlayColor: 'var(--atom-foreground-core-fg-link)', hoverOp: 0.08, activeOp: 0.14, focusOp: 0.05,
  },
  White: {
    bg: 'var(--atom-background-primary-bg-primary-inverse)',
    fg: 'var(--atom-foreground-primary-fg-brand-primary)',
    border: 'none',
    overlayColor: 'rgba(0,0,0,1)', hoverOp: 0.06, activeOp: 0.12, focusOp: 0.04,
  },
  Destructive: {
    bg: 'var(--atom-background-alert-bg-error-full)',
    fg: 'var(--atom-foreground-primary-fg-brand-primary-inverse)',
    border: 'none',
    overlayColor: 'rgba(0,0,0,1)', hoverOp: 0.08, activeOp: 0.16, focusOp: 0.05,
  },
  'Destructive-Text': {
    bg: 'transparent',
    fg: 'var(--atom-foreground-feedback-fg-error)',
    border: 'none',
    overlayColor: 'var(--atom-foreground-feedback-fg-error)', hoverOp: 0.08, activeOp: 0.14, focusOp: 0.05,
  },
};

// ─── ButtonLive ───────────────────────────────────────────────────────────────
export function ButtonLive({
  buttonType = 'Full Button',
  variant = 'Primary',
  size = 'Default',
  state = 'Default',
  label = 'Button Label',
  showIconLeft = false,
  showIconRight = false,
  brand = 'dragonpass',
}: ButtonLiveProps) {
  const isDisabled = state === 'Disabled';
  const isLoading  = state === 'Loading';

  const sharedDisabled: React.CSSProperties = isDisabled
    ? { opacity: 0.4, cursor: 'not-allowed', pointerEvents: 'none' }
    : {};

  const focusRing = state === 'Focus' ? '0 0 0 3px rgba(59,130,246,0.4)' : undefined;

  // ── Payment buttons — layout from Figma: [Button Label][8px][Logo] ──────────
  const s = FULL_SIZE[size];
  const paymentShared: React.CSSProperties = {
    display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
    height: s.height, paddingLeft: s.paddingX, paddingRight: s.paddingX,
    border: 'none', borderRadius: '999px',
    cursor: isDisabled ? 'not-allowed' : 'pointer', outline: 'none',
    boxShadow: focusRing, userSelect: 'none',
    transition: 'opacity 0.15s ease', ...sharedDisabled,
  };

  // GooglePay: black bg, Figma node 8145:7892
  if (buttonType === 'GooglePay') {
    return (
      <button disabled={isDisabled} style={{ ...paymentShared, backgroundColor: '#000000' }}>
        <span style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
          <span style={{
            color: '#ffffff', fontSize: s.fontSize, fontWeight: 500,
            fontFamily: 'var(--atom-font-body, system-ui, sans-serif)',
            lineHeight: '20px', whiteSpace: 'nowrap',
          }}>
            {isLoading ? 'Loading…' : (label || 'Button Label')}
          </span>
          {isLoading ? <SpinnerIcon size={20} /> : <GooglePayLogo />}
        </span>
      </button>
    );
  }

  // ApplePay: black bg, Figma node 8145:7885
  if (buttonType === 'ApplePay') {
    return (
      <button disabled={isDisabled} style={{ ...paymentShared, backgroundColor: '#000000' }}>
        <span style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
          <span style={{
            color: '#ffffff', fontSize: s.fontSize, fontWeight: 500,
            fontFamily: 'var(--atom-font-body, system-ui, sans-serif)',
            lineHeight: '20px', whiteSpace: 'nowrap',
          }}>
            {isLoading ? 'Loading…' : (label || 'Button Label')}
          </span>
          {isLoading ? <SpinnerIcon size={20} /> : <ApplePayLogo />}
        </span>
      </button>
    );
  }

  // PayPal: blue bg rgb(23,155,215), Figma node 8145:7877
  if (buttonType === 'PayPal') {
    return (
      <button disabled={isDisabled} style={{ ...paymentShared, backgroundColor: 'rgb(23,155,215)' }}>
        <span style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
          <span style={{
            color: '#ffffff', fontSize: s.fontSize, fontWeight: 500,
            fontFamily: 'var(--atom-font-body, system-ui, sans-serif)',
            lineHeight: '20px', whiteSpace: 'nowrap',
          }}>
            {isLoading ? 'Loading…' : (label || 'Button Label')}
          </span>
          {isLoading ? <SpinnerIcon size={20} /> : <PayPalLogo />}
        </span>
      </button>
    );
  }

  // ── Icon Only ──────────────────────────────────────────────────────────────
  if (buttonType === 'Icon Only') {
    const v = variant === 'Secondary' ? VARIANT_STYLES.Secondary : VARIANT_STYLES.Primary;
    const dim = ICON_ONLY_SIZE[size];
    const overlayOp =
      state === 'Hover'  ? v.hoverOp  :
      state === 'Active' ? v.activeOp :
      state === 'Focus'  ? v.focusOp  : 0;
    return (
      <button
        disabled={isDisabled}
        aria-label="Icon button"
        style={{
          position: 'relative',
          display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
          width: dim, height: dim,
          backgroundColor: v.bg, color: v.fg, border: v.border,
          borderRadius: '999px',
          cursor: isDisabled ? 'not-allowed' : 'pointer',
          opacity: isDisabled ? 0.4 : 1,
          outline: 'none', boxShadow: focusRing,
          pointerEvents: isDisabled ? 'none' : undefined,
          userSelect: 'none', overflow: 'hidden',
          transition: 'opacity 0.15s ease, box-shadow 0.15s ease',
        }}
      >
        {overlayOp > 0 && (
          <span aria-hidden="true" style={{
            position: 'absolute', inset: 0,
            backgroundColor: v.overlayColor, opacity: overlayOp,
            borderRadius: 'inherit', pointerEvents: 'none',
          }} />
        )}
        {isLoading ? <SpinnerIcon size={20} /> : <PlaceholderIcon brand={brand} size={20} />}
      </button>
    );
  }

  // ── Social Login ───────────────────────────────────────────────────────────
  if (buttonType === 'Social Login') {
    const isSocialPrimary = variant === 'Primary';
    const bg     = isSocialPrimary
      ? 'var(--atom-background-primary-bg-primary-inverse)'   // white
      : 'transparent';
    const fg     = 'var(--atom-foreground-primary-fg-brand-primary)';
    const border = isSocialPrimary
      ? 'none'
      : '1px solid var(--atom-border-default-border-default-brand)';
    return (
      <button
        disabled={isDisabled}
        style={{
          position: 'relative',
          display: 'inline-flex', alignItems: 'center', justifyContent: 'space-between',
          width: '300px', height: FULL_SIZE[size].height,
          paddingLeft: '24px', paddingRight: '24px',
          backgroundColor: bg, color: fg, border,
          borderRadius: '999px',
          fontSize: FULL_SIZE[size].fontSize, fontWeight: 600,
          fontFamily: 'var(--atom-font-body, system-ui, sans-serif)',
          cursor: isDisabled ? 'not-allowed' : 'pointer',
          opacity: isDisabled ? 0.4 : 1,
          outline: 'none', boxShadow: focusRing,
          pointerEvents: isDisabled ? 'none' : undefined,
          userSelect: 'none', overflow: 'hidden',
          transition: 'opacity 0.15s ease, box-shadow 0.15s ease',
        }}
      >
        {/* Provider logo slot (left) */}
        <PlaceholderIcon brand={brand} />
        {/* Centered label */}
        <span style={{ flex: 1, textAlign: 'center' }}>
          {isLoading ? 'Loading…' : (label || 'Continue with Provider')}
        </span>
        {/* Empty right slot (balances layout) */}
        <span style={{ width: '16px', flexShrink: 0 }} />
      </button>
    );
  }

  // ── Full Button (default) ──────────────────────────────────────────────────
  const v = VARIANT_STYLES[variant];
  const overlayOp =
    state === 'Hover'  ? v.hoverOp  :
    state === 'Active' ? v.activeOp :
    state === 'Focus'  ? v.focusOp  : 0;

  return (
    <button
      disabled={isDisabled}
      aria-busy={isLoading ? 'true' : undefined}
      aria-label={isLoading ? 'Loading…' : label}
      style={{
        position: 'relative',
        display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
        height: s.height, paddingLeft: s.paddingX, paddingRight: s.paddingX,
        backgroundColor: v.bg, color: v.fg, border: v.border,
        borderRadius: 'var(--atom-buttons-radius, 999px)',
        fontSize: s.fontSize, fontWeight: 600,
        fontFamily: 'var(--atom-font-body, system-ui, sans-serif)',
        lineHeight: '20px',
        cursor: isDisabled ? 'not-allowed' : 'pointer',
        opacity: isDisabled ? 0.4 : 1,
        outline: 'none', boxShadow: focusRing,
        pointerEvents: isDisabled ? 'none' : undefined,
        whiteSpace: 'nowrap', userSelect: 'none', overflow: 'hidden',
        transition: 'opacity 0.15s ease, box-shadow 0.15s ease',
      }}
    >
      {overlayOp > 0 && (
        <span aria-hidden="true" style={{
          position: 'absolute', inset: 0,
          backgroundColor: v.overlayColor, opacity: overlayOp,
          borderRadius: 'inherit', pointerEvents: 'none',
        }} />
      )}
      {isLoading ? (
        <><SpinnerIcon /><span>Loading…</span></>
      ) : (
        <>
          {showIconLeft  && <PlaceholderIcon brand={brand} />}
          <span>{label || 'Button Label'}</span>
          {showIconRight && <PlaceholderIcon brand={brand} />}
        </>
      )}
    </button>
  );
}
